import React from 'react';
import { Trash2, ShoppingBag, MapPin, AlertCircle } from 'lucide-react';
import { useCart } from '../context/CartContext';

const Carrito = ({ onCheckout }) => {
  const { cart, removeFromCart, total, clearCart } = useCart();

  const handleFinalizarCompra = () => {
    if (cart.length === 0) return;
    // Llamamos a la función que pasamos desde PanelCliente
    onCheckout(total);
  };

  if (cart.length === 0) {
    return (
      <div style={emptyContainer}>
        <ShoppingBag size={64} color="#cbd5e0" />
        <h3 style={{ color: '#4a5568', marginTop: '20px' }}>Tu carrito está vacío</h3>
        <p style={{ color: '#a0aec0' }}>¡Explora las ofertas y llena tu bolsa!</p>
      </div>
    );
  }

  return (
    <div style={container}>
      <div style={header}>
        <h2 style={{ margin: 0, fontSize: '1.5rem' }}>Tu Pedido</h2>
        <button onClick={clearCart} style={btnClear}>Vaciar</button>
      </div>

      <div style={listContainer}>
        {cart.map((item) => (
          <div key={item.idCarrito} style={cardItem}>
            <img 
              src={item.imagenUrl || "/api/placeholder/80/80"} 
              alt={item.producto} 
              style={imgThumb} 
            />
            <div style={{ flex: 1, marginLeft: '15px' }}>
              <h4 style={{ margin: 0, fontSize: '1rem' }}>{item.producto}</h4>
              <small style={{ color: '#718096' }}>{item.local?.nombre || "Local"}</small>
              <div style={priceTag}>${item.precio}</div>
            </div>
            <button 
              onClick={() => removeFromCart(item.idCarrito)} 
              style={btnDelete}
            >
              <Trash2 size={18} />
            </button>
          </div>
        ))}
      </div>

      <div style={footer}>
        <div style={resumenRow}>
          <span>Subtotal</span>
          <span>${total}</span>
        </div>
        <div style={resumenRow}>
          <span>Envío</span>
          <span style={{ color: '#27ae60', fontWeight: 'bold' }}>GRATIS</span>
        </div>
        <hr style={divider} />
        <div style={totalRow}>
          <span>Total</span>
          <span>${total}</span>
        </div>

        <div style={infoBanner}>
          <AlertCircle size={16} />
          <small>El pedido se pagará en efectivo al recibir.</small>
        </div>

        <button onClick={handleFinalizarCompra} style={btnCheckout}>
          Confirmar y Pedir
        </button>
      </div>
    </div>
  );
};

// --- ESTILOS ---
const container = {
  background: 'white',
  borderRadius: '24px',
  padding: '25px',
  boxShadow: '0 10px 25px rgba(0,0,0,0.1)',
  height: 'fit-content'
};

const emptyContainer = {
  display: 'flex',
  flexDirection: 'column',
  alignItems: 'center',
  justifyContent: 'center',
  padding: '60px 20px',
  textAlign: 'center'
};

const header = {
  display: 'flex',
  justifyContent: 'space-between',
  alignItems: 'center',
  marginBottom: '20px'
};

const btnClear = {
  background: 'none',
  border: 'none',
  color: '#e53e3e',
  cursor: 'pointer',
  fontSize: '0.9rem',
  fontWeight: '600'
};

const listContainer = {
  maxHeight: '400px',
  overflowY: 'auto',
  marginBottom: '20px',
  paddingRight: '5px'
};

const cardItem = {
  display: 'flex',
  alignItems: 'center',
  padding: '12px 0',
  borderBottom: '1px solid #edf2f7'
};

const imgThumb = {
  width: '60px',
  height: '60px',
  borderRadius: '12px',
  objectFit: 'cover'
};

const priceTag = {
  fontWeight: 'bold',
  color: '#e67e22',
  marginTop: '4px'
};

const btnDelete = {
  background: '#fff5f5',
  border: 'none',
  padding: '8px',
  borderRadius: '10px',
  color: '#e53e3e',
  cursor: 'pointer',
  transition: '0.2s'
};

const footer = {
  marginTop: '20px',
  padding: '20px',
  background: '#f8fafc',
  borderRadius: '18px'
};

const resumenRow = {
  display: 'flex',
  justifyContent: 'space-between',
  color: '#718096',
  marginBottom: '8px'
};

const totalRow = {
  display: 'flex',
  justifyContent: 'space-between',
  fontSize: '1.2rem',
  fontWeight: 'bold',
  color: '#1a202c',
  margin: '10px 0'
};

const divider = {
  border: 'none',
  borderTop: '1px solid #e2e8f0',
  margin: '15px 0'
};

const infoBanner = {
  display: 'flex',
  alignItems: 'center',
  gap: '8px',
  color: '#4a5568',
  marginBottom: '15px',
  background: '#ebf8ff',
  padding: '10px',
  borderRadius: '10px'
};

const btnCheckout = {
  width: '100%',
  padding: '15px',
  background: '#e67e22',
  color: 'white',
  border: 'none',
  borderRadius: '14px',
  fontSize: '1.1rem',
  fontWeight: 'bold',
  cursor: 'pointer',
  boxShadow: '0 4px 12px rgba(230, 126, 34, 0.3)'
};

export default Carrito;
